@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* Left sidebar — filters *@
    <div class="col-lg-3 mb-3">
        <CatalogFilters Categories="_categories" OnFilterApplied="HandleFilterApplied" />
    </div>

    @* Main content area *@
    <div class="col-lg-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
            </div>
        }
        else if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading products...</span>
                </div>
                <p class="mt-2 text-muted">Loading products...</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="@_totalCount"
                            Page="@_currentPage"
                            PageSize="@_pageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="@_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="@_currentPage"
                               TotalCount="@_totalCount"
                               PageSize="@_pageSize"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    /// <summary>
    /// Raised when a product card is clicked so a parent or layout can navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private List<Product> _products = new();
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _pageSize = 12;
    private int _totalCount;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            ApplyResult(await searchTask);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
            ApplyResult(result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyResult(PagedResult<Product> result)
    {
        _products = result.Items;
        _totalCount = result.TotalCount;
        _currentPage = result.Page;
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire to a cart service when available
        return Task.CompletedTask;
    }
}

